### Step 6: Question Extractor Post-Processor

**File: `/Users/marcus/conductor/workspaces/brain/santo-domingo-v1/app/src/server/chat/post-processors/question-extractor.ts`** (new)

```typescript
import { RecordId, type Surreal } from "surrealdb";
import { createEmbeddingVector } from "../../graph/embeddings";
import { createQuestionRecord, searchEntitiesByEmbedding } from "../../graph/queries";

type ExtractedQuestion = {
  text: string;
  isDuplicate: boolean;
};

const RHETORICAL_PATTERNS = [
  /^right\??$/i,
  /^you know\??$/i,
  /^isn'?t it\??$/i,
  /^don'?t you think\??$/i,
  /^makes sense\??$/i,
  /^got it\??$/i,
  /^okay\??$/i,
  /^yeah\??$/i,
];

export function extractQuestionsFromText(text: string): string[] {
  // Split into sentences (handle "?", ".\n", etc.)
  const sentences = text.split(/(?<=[.!?])\s+/);
  const questions: string[] = [];

  for (const sentence of sentences) {
    const trimmed = sentence.trim();
    if (!trimmed.endsWith("?")) continue;

    // Filter short rhetorical questions (< 4 words)
    const wordCount = trimmed.split(/\s+/).length;
    if (wordCount < 4) continue;

    // Filter known rhetorical patterns
    if (RHETORICAL_PATTERNS.some((re) => re.test(trimmed))) continue;

    questions.push(trimmed);
  }

  return questions;
}

export async function persistArchitectQuestions(input: {
  surreal: Surreal;
  embeddingModel: any;
  embeddingDimension: number;
  workspaceRecord: RecordId<"workspace", string>;
  sourceMessageRecord: RecordId<"message", string>;
  questions: string[];
}): Promise<number> {
  let created = 0;

  for (const questionText of input.questions) {
    // Dedup via embedding similarity
    const embedding = await createEmbeddingVector(
      input.embeddingModel,
      questionText,
      input.embeddingDimension,
    );
    if (!embedding) continue;

    const similar = await searchEntitiesByEmbedding({
      surreal: input.surreal,
      workspaceRecord: input.workspaceRecord,
      queryEmbedding: embedding,
      kinds: ["question"],
      limit: 3,
    });

    // Skip if highly similar question exists (>0.92 cosine)
    const isDuplicate = similar.some((s) => s.similarity > 0.92);
    if (isDuplicate) continue;

    await createQuestionRecord({
      surreal: input.surreal,
      text: questionText,
      status: "asked",
      workspaceRecord: input.workspaceRecord,
      sourceMessageRecord: input.sourceMessageRecord,
      embedding,
      now: new Date(),
    });
    created++;
  }

  return created;
}
```

**Integration in processor** (`chat-processor.ts`): After the chat agent response, when in architect mode:

```typescript
// After graphAwareResponse is captured (around line 210):
if (agentMode === "architect") {
  const questions = extractQuestionsFromText(graphAwareResponse.text);
  if (questions.length > 0) {
