```typescript
import { RecordId, type Surreal } from "surrealdb";
import { createEmbeddingVector } from "../../graph/embeddings";
import { listWorkspaceOpenQuestions, searchEntitiesByEmbedding } from "../../graph/queries";

const DEFERRAL_PATTERNS = [
  /\bi'?ll think about (it|that)\b/i,
  /\bnot sure yet\b/i,
  /\blater\b/i,
  /\blet me think\b/i,
  /\bcome back to (that|this)\b/i,
];

export async function detectAnswersAndDeferrals(input: {
  surreal: Surreal;
  embeddingModel: any;
  embeddingDimension: number;
  workspaceRecord: RecordId<"workspace", string>;
  userText: string;
}): Promise<void> {
  // Check for deferrals
  if (DEFERRAL_PATTERNS.some((re) => re.test(input.userText))) {
    // Could mark recent open questions as "deferred" but for v1,
    // leave as-is. The Architect agent will naturally re-raise them.
    return;
  }

  // Check if user text semantically matches any open question
  const embedding = await createEmbeddingVector(
    input.embeddingModel,
    input.userText,
    input.embeddingDimension,
  );
  if (!embedding) return;

  const similar = await searchEntitiesByEmbedding({
    surreal: input.surreal,
    workspaceRecord: input.workspaceRecord,
    queryEmbedding: embedding,
    kinds: ["question"],
    limit: 3,
  });

  // If user text is highly similar to an open question, mark it answered
  for (const match of similar) {
    if (match.similarity > 0.85 && match.status === "asked") {
      await input.surreal.query(
        "UPDATE $question SET status = 'answered', answer_summary = $summary, updated_at = $now;",
        {
          question: new RecordId("question", match.id),
          summary: input.userText.slice(0, 500),
          now: new Date(),
        },
      );
    }
  }
}
```

**Note**: The question schema does NOT currently have `answer_summary` or `asked_by` fields with answer-related statuses. A migration is needed (Step 9).

