  1→import { RecordId } from "surrealdb";
  2→import type { ExtractedEntity, ExtractedRelationship, OnboardingAction } from "../../shared/contracts";
  3→import { loadAssistantConversationContext } from "../extraction/context-loaders";
  4→import { loadBranchChain, loadMessagesWithInheritance } from "./branch-chain";
  5→import { ingestAttachment } from "../extraction/document-ingestion";
  6→import { createEmbedding, persistEmbeddings } from "../extraction/embedding-writeback";
  7→import { appendExtractedTools } from "../extraction/persist-extraction";
  8→import type { ConversationRow, GraphEntityRecord, IncomingAttachment, WorkspaceRow } from "../extraction/types";
  9→import { elapsedMs, logError, logInfo, userFacingError } from "../http/observability";
 10→import { transitionOnboardingState } from "../onboarding/onboarding-state";
 11→import type { ServerDependencies } from "../runtime/types";
 12→import { runChatAgent } from "./handler";
 13→import { getWorkspaceOwnerRecord } from "../graph/queries";
 14→import { refreshConversationTouchedBy, maybeUpgradeConversationTitle } from "../workspace/conversation-sidebar";
 15→import { loadWorkspaceProjects } from "../workspace/workspace-scope";
 16→
 17→export async function processChatMessage(input: {
 18→  deps: ServerDependencies;
 19→  conversationId: string;
 20→  messageId: string;
 21→  workspaceRecord: RecordId<"workspace", string>;
 22→  userMessageRecord: RecordId<"message", string>;
 23→  userText: string;
 24→  attachment?: IncomingAttachment;
 25→  onboardingAction?: OnboardingAction;
 26→  personRecord: RecordId<"person", string>;
 27→}): Promise<void> {
 28→  const startedAt = performance.now();
 29→  logInfo("chat.message.process.execution.started", "Chat message processing execution started", {
 30→    conversationId: input.conversationId,
 31→    messageId: input.messageId,
 32→    workspaceId: input.workspaceRecord.id as string,
 33→    hasAttachment: input.attachment !== undefined,
 34→  });
 35→
 36→  try {
 37→    const now = new Date();
 38→    const conversationRecord = new RecordId("conversation", input.conversationId);
 39→    const workspace = await input.deps.surreal.select<WorkspaceRow>(input.workspaceRecord);
 40→    if (!workspace) {
 41→      throw new Error("workspace not found");
 42→    }
 43→
 44→    const conversation = await input.deps.surreal.select<ConversationRow>(conversationRecord);
 45→    if (!conversation) {
 46→      throw new Error("conversation not found");
 47→    }
 48→
 49→    // Check if this conversation is a branch and load inherited context
 50→    const branchChain = await loadBranchChain(input.deps.surreal, input.conversationId);
 51→    const isBranch = branchChain.length > 0;
 52→
 53→    let inheritedEntityIds: RecordId[] | undefined;
 54→    let assistantContextRows: Array<{ id: RecordId<"message", string>; role: "user" | "assistant"; text: string; createdAt: Date | string }>;
 55→
 56→    if (isBranch) {
 57→      // For branches, load full message history including inherited messages
 58→      const allMessages = await loadMessagesWithInheritance(input.deps.surreal, input.conversationId, 30);
 59→      assistantContextRows = allMessages
 60→        .map((m) => ({
 61→          id: new RecordId("message", m.id),
 62→          role: m.role,
 63→          text: m.text,
 64→          createdAt: m.createdAt,
 65→        }))
 66→        .slice(-10);
 67→
 68→      // Derive inherited entity IDs from extraction_relations on inherited messages
 69→      const inheritedMsgIds = allMessages
 70→        .filter((m) => m.inherited)
 71→        .map((m) => new RecordId("message", m.id));
 72→
 73→      if (inheritedMsgIds.length > 0) {
 74→        const [entityRows] = await input.deps.surreal
 75→          .query<[Array<{ out: RecordId }>]>(
 76→            "SELECT DISTINCT out FROM extraction_relation WHERE `in` IN $msgIds LIMIT 30;",
 77→            { msgIds: inheritedMsgIds },
 78→          )
 79→          .collect<[Array<{ out: RecordId }>]>();
 80→        inheritedEntityIds = entityRows.map((r) => r.out);
 81→      }
 82→    } else {
 83→      assistantContextRows = await loadAssistantConversationContext(input.deps.surreal, input.conversationId);
 84→    }
 85→
 86→    // Embed user message early: used for context enrichment and persisted to the message record
 87→    const userMessageEmbedding = await createEmbedding(input.deps.embeddingModel, input.deps.config.embeddingDimension, input.userText);
 88→    if (userMessageEmbedding) {
 89→      void input.deps.surreal
 90→        .query("UPDATE $record MERGE { embedding: $embedding };", {
 91→          record: input.userMessageRecord,
 92→          embedding: userMessageEmbedding,
 93→        })
 94→        .catch(() => undefined);
 95→    }
 96→
 97→    const workspaceProjects = await loadWorkspaceProjects(input.deps.surreal, input.workspaceRecord);
 98→    const workspaceProjectNames = workspaceProjects.map((project) => project.name);
 99→    const persistedEntities: ExtractedEntity[] = [];
100→    const persistedRelationships: ExtractedRelationship[] = [];
101→    const embeddingTargets: Array<{ record: GraphEntityRecord; text: string }> = [];
102→    const extractedTools: string[] = [];
103→    const unresolvedAssigneeNames = new Set<string>();
104→
105→    // Attachment extraction stays automatic — document ingestion is intentional
106→    if (input.attachment) {
107→      const ingestion = await ingestAttachment({
108→        surreal: input.deps.surreal,
109→        extractionModel: input.deps.extractionModel,
110→        embeddingModel: input.deps.embeddingModel,
111→        embeddingDimension: input.deps.config.embeddingDimension,
112→        extractionStoreThreshold: input.deps.config.extractionStoreThreshold,
113→        extractionModelId: input.deps.config.extractionModelId,
114→        workspaceRecord: input.workspaceRecord,
115→        conversationRecord,
116→        userMessageRecord: input.userMessageRecord,
117→        attachment: input.attachment,
118→        workspaceName: workspace.name,
119→        projectNames: workspaceProjectNames,
120→        now,
121→        onChunkResult: (chunkResult) => {
122→          if (chunkResult.entities.length > 0 || chunkResult.relationships.length > 0) {
123→            input.deps.sse.emitEvent(input.messageId, {
124→              type: "extraction",
125→              messageId: input.messageId,
126→              entities: chunkResult.entities,
127→              relationships: chunkResult.relationships,
128→            });
129→          }
130→        },
131→      });
132→
133→      persistedEntities.push(...ingestion.entities);
134→      persistedRelationships.push(...ingestion.relationships);
135→      embeddingTargets.push(...ingestion.embeddingTargets);
136→      extractedTools.push(...ingestion.tools);
137→      for (const unresolvedName of ingestion.unresolvedAssigneeNames) {
138→        unresolvedAssigneeNames.add(unresolvedName);
139→      }
140→    }
141→
142→    if (extractedTools.length > 0) {
143→      await appendExtractedTools(input.deps.surreal, input.workspaceRecord, extractedTools, now);
144→    }
145→
146→    const onboardingBefore = workspace.onboarding_complete
147→      ? "complete"
148→      : workspace.onboarding_summary_pending
149→        ? "summary_pending"
150→        : "active";
151→
152→    const onboardingAfter = await transitionOnboardingState({
153→      surreal: input.deps.surreal,
154→      workspaceRecord: input.workspaceRecord,
155→      workspace,
156→      onboardingAction: input.onboardingAction,
157→      now,
158→    });
159→
160→    // Always run chat agent — it handles both onboarding and post-onboarding
161→    const workspaceOwnerRecord = await getWorkspaceOwnerRecord({
162→      surreal: input.deps.surreal,
163→      workspaceRecord: input.workspaceRecord,
164→    });
165→
166→    const graphAwareResponse = await runChatAgent({
167→      surreal: input.deps.surreal,
168→      model: input.deps.chatAgentModel,
169→      pmAgentModel: input.deps.pmAgentModel,
170→      analyticsAgentModel: input.deps.analyticsAgentModel,
171→      analyticsSurreal: input.deps.analyticsSurreal,
172→      embeddingModel: input.deps.embeddingModel,
173→      embeddingDimension: input.deps.config.embeddingDimension,
174→      extractionModelId: input.deps.config.extractionModelId,
175→      extractionModel: input.deps.extractionModel,
176→      extractionStoreThreshold: input.deps.config.extractionStoreThreshold,
177→      conversationRecord,
178→      workspaceRecord: input.workspaceRecord,
179→      currentMessageRecord: input.userMessageRecord,
180→      latestUserText: input.userText,
181→      isOnboarding: onboardingAfter !== "complete",
182→      onboardingState: onboardingAfter,
183→      ...(workspaceOwnerRecord ? { workspaceOwnerRecord } : {}),
184→      personRecord: input.personRecord,
185→      ...(userMessageEmbedding ? { userMessageEmbedding } : {}),
186→      ...(inheritedEntityIds && inheritedEntityIds.length > 0 ? { inheritedEntityIds } : {}),
187→      ...(conversation.discusses ? { discussesRecord: conversation.discusses } : {}),
188→      messages: assistantContextRows.map((row) => ({
