  1→import { type RecordId, type Surreal } from "surrealdb";
  2→import type { ObservationSummary, OnboardingState, SuggestionSummary } from "../../shared/contracts";
  3→import {
  4→  listConversationEntities,
  5→  listWorkspaceOpenQuestions,
  6→  listWorkspaceProjectSummaries,
  7→  listWorkspaceRecentDecisions,
  8→  readEntityName,
  9→  searchEntitiesByEmbedding,
 10→  type ConversationEntity,
 11→  type RankedEntity,
 12→  type WorkspaceDecisionSummary,
 13→  type WorkspaceProjectSummary,
 14→  type WorkspaceQuestionSummary,
 15→} from "../graph/queries";
 16→import { listWorkspaceOpenObservations } from "../observation/queries";
 17→import { listWorkspacePendingSuggestions } from "../suggestion/queries";
 18→import { loadOnboardingSummary } from "../onboarding/onboarding-state";
 19→import type { GraphEntityRecord } from "../extraction/types";
 20→
 21→export type DiscussedEntityContext = {
 22→  kind: string;
 23→  name: string;
 24→  status?: string;
 25→};
 26→
 27→export type ChatContext = {
 28→  conversationEntities: ConversationEntity[];
 29→  relevantEntities?: RankedEntity[];
 30→  workspaceSummary: {
 31→    projects: WorkspaceProjectSummary[];
 32→    recentDecisions: WorkspaceDecisionSummary[];
 33→    openQuestions: WorkspaceQuestionSummary[];
 34→    openObservations: ObservationSummary[];
 35→    pendingSuggestions: SuggestionSummary[];
 36→  };
 37→  onboardingSummary?: string;
 38→  discussedEntity?: DiscussedEntityContext;
 39→};
 40→
 41→type ChatContextLoaders = {
 42→  listConversationEntities: typeof listConversationEntities;
 43→  listWorkspaceProjectSummaries: typeof listWorkspaceProjectSummaries;
 44→  listWorkspaceRecentDecisions: typeof listWorkspaceRecentDecisions;
 45→  listWorkspaceOpenQuestions: typeof listWorkspaceOpenQuestions;
 46→  listWorkspaceOpenObservations: typeof listWorkspaceOpenObservations;
 47→  listWorkspacePendingSuggestions: typeof listWorkspacePendingSuggestions;
 48→  loadOnboardingSummary: typeof loadOnboardingSummary;
 49→};
 50→
 51→export async function buildChatContext(input: {
 52→  surreal: Surreal;
 53→  conversationRecord: RecordId<"conversation", string>;
 54→  workspaceRecord: RecordId<"workspace", string>;
 55→  loaders?: ChatContextLoaders;
 56→  inheritedEntityIds?: RecordId[];
 57→  discussesRecord?: RecordId;
 58→  userMessageEmbedding?: number[];
 59→}): Promise<ChatContext> {
 60→  const loaders = input.loaders ?? {
 61→    listConversationEntities,
 62→    listWorkspaceProjectSummaries,
 63→    listWorkspaceRecentDecisions,
 64→    listWorkspaceOpenQuestions,
 65→    listWorkspaceOpenObservations,
 66→    listWorkspacePendingSuggestions,
 67→    loadOnboardingSummary,
 68→  };
 69→
 70→  const [conversationEntities, projects, recentDecisions, openQuestions, openObservations, pendingSuggestions, onboardingSummary] = await Promise.all([
 71→    loaders.listConversationEntities({
 72→      surreal: input.surreal,
 73→      conversationRecord: input.conversationRecord,
 74→      workspaceRecord: input.workspaceRecord,
 75→      limit: 60,
 76→      ...(input.inheritedEntityIds && input.inheritedEntityIds.length > 0
 77→        ? { inheritedEntityIds: input.inheritedEntityIds }
 78→        : {}),
 79→    }),
 80→    loaders.listWorkspaceProjectSummaries({
 81→      surreal: input.surreal,
 82→      workspaceRecord: input.workspaceRecord,
 83→      limit: 20,
 84→    }),
 85→    loaders.listWorkspaceRecentDecisions({
 86→      surreal: input.surreal,
 87→      workspaceRecord: input.workspaceRecord,
 88→      limit: 12,
 89→    }),
 90→    loaders.listWorkspaceOpenQuestions({
 91→      surreal: input.surreal,
 92→      workspaceRecord: input.workspaceRecord,
 93→      limit: 12,
 94→    }),
 95→    loaders.listWorkspaceOpenObservations({
 96→      surreal: input.surreal,
 97→      workspaceRecord: input.workspaceRecord,
 98→      limit: 10,
 99→    }),
100→    loaders.listWorkspacePendingSuggestions({
101→      surreal: input.surreal,
102→      workspaceRecord: input.workspaceRecord,
103→      limit: 10,
104→    }),
105→    loaders.loadOnboardingSummary(input.surreal, input.workspaceRecord),
106→  ]);
107→
108→  // Cross-conversation entity enrichment: find workspace entities relevant to the user's message
109→  let relevantEntities: RankedEntity[] | undefined;
110→  if (input.userMessageEmbedding) {
111→    const queryEmbedding = input.userMessageEmbedding;
112→    const conversationEntityIds = new Set(
113→      conversationEntities.map((e) => e.id),
114→    );
115→    const ranked = await searchEntitiesByEmbedding({
116→      surreal: input.surreal,
117→      workspaceRecord: input.workspaceRecord,
118→      queryEmbedding,
119→      limit: 15,
120→    });
121→    const filtered = ranked.filter((e) => !conversationEntityIds.has(e.id));
122→    if (filtered.length > 0) {
123→      relevantEntities = filtered.slice(0, 10);
124→    }
125→  }
126→
127→  let discussedEntity: DiscussedEntityContext | undefined;
128→  if (input.discussesRecord) {
129→    const entityRecord = input.discussesRecord as GraphEntityRecord;
130→    const name = await readEntityName(input.surreal, entityRecord);
131→    if (name) {
132→      const row = await input.surreal.select<Record<string, unknown>>(entityRecord);
133→      discussedEntity = {
134→        kind: entityRecord.table.name,
135→        name,
136→        ...(row && typeof row.status === "string" ? { status: row.status } : {}),
137→      };
138→    }
139→  }
140→
141→  return {
142→    conversationEntities,
143→    relevantEntities,
144→    workspaceSummary: {
145→      projects,
146→      recentDecisions,
147→      openQuestions,
148→      openObservations,
149→      pendingSuggestions,
150→    },
151→    onboardingSummary,
152→    discussedEntity,
153→  };
154→}
155→
156→function formatConversationEntities(entities: ConversationEntity[]): string {
157→  if (entities.length === 0) {
158→    return "- none";
159→  }
160→
161→  return entities
162→    .slice(0, 20)
163→    .map((entity) => `- ${entity.kind}: ${entity.name} (confidence ${entity.confidence.toFixed(2)})`)
164→    .join("\n");
165→}
166→
167→
168→function formatRelevantEntities(entities: RankedEntity[]): string {
169→  return entities
170→    .map((e) => `- ${e.kind}: ${e.name} (relevance ${e.score.toFixed(2)})`)
171→    .join("\n");
172→}
173→
174→function formatWorkspaceSummary(context: ChatContext): string {
175→  const { projects, recentDecisions, openQuestions, openObservations, pendingSuggestions } = context.workspaceSummary;
176→
177→  const lines: string[] = [];
178→
179→  // Projects: keep names since they're needed for routing
180→  if (projects.length === 0) {
181→    lines.push("- Projects: none");
182→  } else {
183→    lines.push(`- Projects: ${projects.map((p) => p.name).join(", ")}`);
184→  }
185→
186→  // Decisions: count by status
187→  if (recentDecisions.length === 0) {
188→    lines.push("- Decisions: none");
189→  } else {
190→    const statusCounts = new Map<string, number>();
191→    for (const d of recentDecisions) {
192→      statusCounts.set(d.status, (statusCounts.get(d.status) ?? 0) + 1);
193→    }
194→    const breakdown = [...statusCounts.entries()].map(([s, c]) => `${c} ${s}`).join(", ");
195→    lines.push(`- Decisions: ${recentDecisions.length} (${breakdown})`);
196→  }
197→
198→  // Questions: just count
199→  lines.push(`- Open questions: ${openQuestions.length}`);
200→
201→  // Observations: count by severity
202→  if (openObservations.length === 0) {
203→    lines.push("- Observations: none");
204→  } else {
205→    const severityCounts = new Map<string, number>();
206→    for (const o of openObservations) {
207→      severityCounts.set(o.severity, (severityCounts.get(o.severity) ?? 0) + 1);
208→    }
209→    const breakdown = [...severityCounts.entries()].map(([s, c]) => `${c} ${s}`).join(", ");
210→    lines.push(`- Observations: ${openObservations.length} (${breakdown})`);
211→  }
212→
213→  // Suggestions: count by category
214→  if (pendingSuggestions.length === 0) {
215→    lines.push("- Suggestions: none");
216→  } else {
217→    const categoryCounts = new Map<string, number>();
218→    for (const s of pendingSuggestions) {
219→      categoryCounts.set(s.category, (categoryCounts.get(s.category) ?? 0) + 1);
220→    }
221→    const breakdown = [...categoryCounts.entries()].map(([c, n]) => `${n} ${c}`).join(", ");
222→    lines.push(`- Suggestions: ${pendingSuggestions.length} (${breakdown})`);
223→  }
224→
225→  return lines.join("\n");
226→}
227→
228→type SystemPromptOptions = {
229→  isOnboarding?: boolean;
230→  onboardingState?: OnboardingState;
231→};
