import { stepCountIs, streamText, type ModelMessage } from "ai";
import { RecordId, Surreal } from "surrealdb";
import type { ExtractedEntity, ExtractedRelationship, OnboardingState } from "../../shared/contracts";
import { logInfo, logError } from "../http/observability";
import { buildChatContext, buildSystemPrompt, type ChatContext } from "./context";
import { createChatAgentTools } from "./tools";

type ConversationMessage = {
  role: "user" | "assistant";
  text: string;
};

type CollectedEntity = ExtractedEntity;
type CollectedRelationship = ExtractedRelationship;

export type ChatAgentResult = {
  text: string;
  collectedEntities: CollectedEntity[];
  collectedRelationships: CollectedRelationship[];
  toolCalls: Array<{ name: string; args: Record<string, unknown> }>;
};

export async function runChatAgent(input: {
  surreal: Surreal;
  model: any;
  pmAgentModel: any;
  analyticsAgentModel: any;
  analyticsSurreal: Surreal;
  architectModel: any;
  embeddingModel: any;
  embeddingDimension: number;
  extractionModelId: string;
  extractionModel: any;
  extractionStoreThreshold: number;
  conversationRecord: RecordId<"conversation", string>;
  workspaceRecord: RecordId<"workspace", string>;
  currentMessageRecord: RecordId<"message", string>;
  latestUserText: string;
  workspaceOwnerRecord?: RecordId<"person", string>;
  personRecord: RecordId<"person", string>;
  userMessageEmbedding?: number[];
  inheritedEntityIds?: RecordId[];
  discussesRecord?: RecordId;
  messages: ConversationMessage[];
  isOnboarding?: boolean;
  onboardingState?: OnboardingState;
  onToken: (token: string) => Promise<void> | void;
  onReasoning?: (token: string) => Promise<void> | void;
}): Promise<ChatAgentResult> {
  const context = await buildChatContext({
    surreal: input.surreal,
    conversationRecord: input.conversationRecord,
    workspaceRecord: input.workspaceRecord,
    ...(input.userMessageEmbedding ? { userMessageEmbedding: input.userMessageEmbedding } : {}),
    ...(input.inheritedEntityIds && input.inheritedEntityIds.length > 0
      ? { inheritedEntityIds: input.inheritedEntityIds }
      : {}),
    ...(input.discussesRecord ? { discussesRecord: input.discussesRecord } : {}),
  });

  const system = buildSystemPrompt(context, {
    isOnboarding: input.isOnboarding,
    onboardingState: input.onboardingState,
  });

  const modelMessages: ModelMessage[] = input.messages.map((message) => ({
    role: message.role,
    content: message.text,
  }));

  const result = streamText({
    model: input.model,
    system,
    messages: modelMessages,
    tools: createChatAgentTools({
      surreal: input.surreal,
      pmAgentModel: input.pmAgentModel,
      analyticsAgentModel: input.analyticsAgentModel,
      analyticsSurreal: input.analyticsSurreal,
      embeddingModel: input.embeddingModel,
      embeddingDimension: input.embeddingDimension,
      extractionModelId: input.extractionModelId,
      extractionModel: input.extractionModel,
      extractionStoreThreshold: input.extractionStoreThreshold,
    }),
    experimental_context: {
      actor: "chat_agent",
      humanPresent: true,
      workspaceRecord: input.workspaceRecord,
      conversationRecord: input.conversationRecord,
      currentMessageRecord: input.currentMessageRecord,
      latestUserText: input.latestUserText,
      ...(input.workspaceOwnerRecord ? { workspaceOwnerRecord: input.workspaceOwnerRecord } : {}),
      personRecord: input.personRecord,
    },
    stopWhen: stepCountIs(5),
  });

  let text = "";
  const collectedEntities: CollectedEntity[] = [];
  const collectedRelationships: CollectedRelationship[] = [];
  const toolCalls: Array<{ name: string; args: Record<string, unknown> }> = [];

  for await (const part of result.fullStream) {
    if (part.type === "reasoning-delta") {
      await input.onReasoning?.(part.text);
      continue;
    }

    if (part.type === "text-delta") {
      text = `${text}${part.text}`;
      await input.onToken(part.text);
      continue;
    }

    if (part.type === "tool-call") {
      logInfo("chat.agent.tool_call", "Chat agent invoked tool", part);
      toolCalls.push({ name: part.toolName, args: (part as any).input as Record<string, unknown> });
    }

    if (part.type === "tool-result") {
      logInfo("chat.agent.tool_result", "Chat agent tool returned", part);
      const toolResult = part.output as Record<string, unknown> | undefined;
      if (toolResult) {
        if (Array.isArray(toolResult.extracted_entities)) {
          collectedEntities.push(...(toolResult.extracted_entities as CollectedEntity[]));
        }
        if (Array.isArray(toolResult.extracted_relationships)) {
          collectedRelationships.push(...(toolResult.extracted_relationships as CollectedRelationship[]));
        }
      }
    }

    if (part.type === "error") {
      logError("chat.agent.stream_error", "Chat agent stream error", part.error, {});
    }
  }

  if (text.trim().length === 0) {
    text = await result.text;
  }

  // Post-process: inject entity:// links for entity names mentioned in the response.
  const linked = injectEntityLinks(text, context);
  if (linked !== text) {
    // Re-send the full linked text as a replacement.
    // The SSE stream already sent raw text; the persisted version will have links.
    text = linked;
  }

  return {
    text: text.trim(),
    collectedEntities,
    collectedRelationships,
    toolCalls,
  };
}

export const runGraphAwareChat = runChatAgent;

type KnownEntity = { entityId: string; kind: string; name: string };

/**
 * Replace entity name mentions in response text with markdown links:
 *   "Model for Extraction Pipeline" → "[Model for Extraction Pipeline](entity://decision:uuid)"
 *
 * Matches longest names first to avoid partial replacement.
 * Only replaces the first occurrence of each entity name.
 */
function injectEntityLinks(text: string, context: ChatContext): string {
  const entities: KnownEntity[] = [];

  for (const project of context.workspaceSummary.projects) {
    entities.push({ entityId: `project:${project.id}`, kind: "project", name: project.name });
  }
  for (const decision of context.workspaceSummary.recentDecisions) {
    entities.push({ entityId: `decision:${decision.id}`, kind: "decision", name: decision.name });
  }
  for (const question of context.workspaceSummary.openQuestions) {
    entities.push({ entityId: `question:${question.id}`, kind: "question", name: question.name });
  }

  // Sort longest name first so "Agent-Native Business OS" matches before "Agent"
  entities.sort((a, b) => b.name.length - a.name.length);

  const replaced = new Set<string>();
  let result = text;

  for (const entity of entities) {
    if (entity.name.length < 3) continue;
    if (replaced.has(entity.entityId)) continue;

    // Case-insensitive match, but only replace the first occurrence.
    // Skip if the name is already inside a markdown link.
    const idx = result.toLowerCase().indexOf(entity.name.toLowerCase());
    if (idx === -1) continue;

    // Check if already inside a markdown link: [...](...)
    const before = result.slice(0, idx);
    if (before.lastIndexOf("[") > before.lastIndexOf("]")) continue;

    const matched = result.slice(idx, idx + entity.name.length);
    const link = `[${matched}](#entity/${entity.entityId})`;
    result = `${result.slice(0, idx)}${link}${result.slice(idx + entity.name.length)}`;
    replaced.add(entity.entityId);
  }

  return result;
}

import { RecordId } from "surrealdb";
import type { ExtractedEntity, ExtractedRelationship, OnboardingAction } from "../../shared/contracts";
import { loadAssistantConversationContext } from "../extraction/context-loaders";
import { loadBranchChain, loadMessagesWithInheritance } from "./branch-chain";
import { ingestAttachment } from "../extraction/document-ingestion";
import { createEmbedding, persistEmbeddings } from "../extraction/embedding-writeback";
import { appendExtractedTools } from "../extraction/persist-extraction";
import type { ConversationRow, GraphEntityRecord, IncomingAttachment, WorkspaceRow } from "../extraction/types";
import { elapsedMs, logError, logInfo, userFacingError } from "../http/observability";
import { transitionOnboardingState } from "../onboarding/onboarding-state";
import type { ServerDependencies } from "../runtime/types";
import { runChatAgent } from "./handler";
import { getWorkspaceOwnerRecord } from "../graph/queries";
import { refreshConversationTouchedBy, maybeUpgradeConversationTitle } from "../workspace/conversation-sidebar";
import { loadWorkspaceProjects } from "../workspace/workspace-scope";

export async function processChatMessage(input: {
  deps: ServerDependencies;
  conversationId: string;
  messageId: string;
  workspaceRecord: RecordId<"workspace", string>;
  userMessageRecord: RecordId<"message", string>;
  userText: string;
  attachment?: IncomingAttachment;
  onboardingAction?: OnboardingAction;
  personRecord: RecordId<"person", string>;
}): Promise<void> {
  const startedAt = performance.now();
  logInfo("chat.message.process.execution.started", "Chat message processing execution started", {
    conversationId: input.conversationId,
    messageId: input.messageId,
    workspaceId: input.workspaceRecord.id as string,
    hasAttachment: input.attachment !== undefined,
  });

  try {
    const now = new Date();
    const conversationRecord = new RecordId("conversation", input.conversationId);
    const workspace = await input.deps.surreal.select<WorkspaceRow>(input.workspaceRecord);
    if (!workspace) {
      throw new Error("workspace not found");
    }

    const conversation = await input.deps.surreal.select<ConversationRow>(conversationRecord);
    if (!conversation) {
      throw new Error("conversation not found");
    }

    // Check if this conversation is a branch and load inherited context
    const branchChain = await loadBranchChain(input.deps.surreal, input.conversationId);
    const isBranch = branchChain.length > 0;

    let inheritedEntityIds: RecordId[] | undefined;
    let assistantContextRows: Array<{ id: RecordId<"message", string>; role: "user" | "assistant"; text: string; createdAt: Date | string }>;

    if (isBranch) {
      // For branches, load full message history including inherited messages
      const allMessages = await loadMessagesWithInheritance(input.deps.surreal, input.conversationId, 30);
      assistantContextRows = allMessages
        .map((m) => ({
          id: new RecordId("message", m.id),
          role: m.role,
          text: m.text,
          createdAt: m.createdAt,
        }))
        .slice(-10);

      // Derive inherited entity IDs from extraction_relations on inherited messages
      const inheritedMsgIds = allMessages
        .filter((m) => m.inherited)
        .map((m) => new RecordId("message", m.id));

      if (inheritedMsgIds.length > 0) {
        const [entityRows] = await input.deps.surreal
          .query<[Array<{ out: RecordId }>]>(
            "SELECT DISTINCT out FROM extraction_relation WHERE `in` IN $msgIds LIMIT 30;",
            { msgIds: inheritedMsgIds },
          )
          .collect<[Array<{ out: RecordId }>]>();
        inheritedEntityIds = entityRows.map((r) => r.out);
      }
    } else {
      assistantContextRows = await loadAssistantConversationContext(input.deps.surreal, input.conversationId);
    }

    // Embed user message early: used for context enrichment and persisted to the message record
    const userMessageEmbedding = await createEmbedding(input.deps.embeddingModel, input.deps.config.embeddingDimension, input.userText);
    if (userMessageEmbedding) {
      void input.deps.surreal
        .query("UPDATE $record MERGE { embedding: $embedding };", {
          record: input.userMessageRecord,
          embedding: userMessageEmbedding,
        })
        .catch(() => undefined);
    }

    const workspaceProjects = await loadWorkspaceProjects(input.deps.surreal, input.workspaceRecord);
    const workspaceProjectNames = workspaceProjects.map((project) => project.name);
    const persistedEntities: ExtractedEntity[] = [];
    const persistedRelationships: ExtractedRelationship[] = [];
    const embeddingTargets: Array<{ record: GraphEntityRecord; text: string }> = [];
    const extractedTools: string[] = [];
    const unresolvedAssigneeNames = new Set<string>();

    // Attachment extraction stays automatic — document ingestion is intentional
    if (input.attachment) {
      const ingestion = await ingestAttachment({
        surreal: input.deps.surreal,
        extractionModel: input.deps.extractionModel,
        embeddingModel: input.deps.embeddingModel,
        embeddingDimension: input.deps.config.embeddingDimension,
        extractionStoreThreshold: input.deps.config.extractionStoreThreshold,
        extractionModelId: input.deps.config.extractionModelId,
        workspaceRecord: input.workspaceRecord,
        conversationRecord,
        userMessageRecord: input.userMessageRecord,
        attachment: input.attachment,
        workspaceName: workspace.name,
        projectNames: workspaceProjectNames,
        now,
        onChunkResult: (chunkResult) => {
          if (chunkResult.entities.length > 0 || chunkResult.relationships.length > 0) {
            input.deps.sse.emitEvent(input.messageId, {
              type: "extraction",
              messageId: input.messageId,
              entities: chunkResult.entities,
              relationships: chunkResult.relationships,
            });
          }
        },
      });

      persistedEntities.push(...ingestion.entities);
      persistedRelationships.push(...ingestion.relationships);
      embeddingTargets.push(...ingestion.embeddingTargets);
      extractedTools.push(...ingestion.tools);
      for (const unresolvedName of ingestion.unresolvedAssigneeNames) {
        unresolvedAssigneeNames.add(unresolvedName);
      }
    }

    if (extractedTools.length > 0) {
      await appendExtractedTools(input.deps.surreal, input.workspaceRecord, extractedTools, now);
    }

    const onboardingBefore = workspace.onboarding_complete
      ? "complete"
      : workspace.onboarding_summary_pending
        ? "summary_pending"
        : "active";

    const onboardingAfter = await transitionOnboardingState({
      surreal: input.deps.surreal,
      workspaceRecord: input.workspaceRecord,
      workspace,
      onboardingAction: input.onboardingAction,
      now,
    });

    // Always run chat agent — it handles both onboarding and post-onboarding
    const workspaceOwnerRecord = await getWorkspaceOwnerRecord({
      surreal: input.deps.surreal,
      workspaceRecord: input.workspaceRecord,
    });

    const graphAwareResponse = await runChatAgent({
      surreal: input.deps.surreal,
      model: input.deps.chatAgentModel,
      pmAgentModel: input.deps.pmAgentModel,
      analyticsAgentModel: input.deps.analyticsAgentModel,
      analyticsSurreal: input.deps.analyticsSurreal,
      embeddingModel: input.deps.embeddingModel,
      embeddingDimension: input.deps.config.embeddingDimension,
      extractionModelId: input.deps.config.extractionModelId,
      extractionModel: input.deps.extractionModel,
      extractionStoreThreshold: input.deps.config.extractionStoreThreshold,
      conversationRecord,
      workspaceRecord: input.workspaceRecord,
      currentMessageRecord: input.userMessageRecord,
      latestUserText: input.userText,
      isOnboarding: onboardingAfter !== "complete",
      onboardingState: onboardingAfter,
      ...(workspaceOwnerRecord ? { workspaceOwnerRecord } : {}),
      personRecord: input.personRecord,
      ...(userMessageEmbedding ? { userMessageEmbedding } : {}),
      ...(inheritedEntityIds && inheritedEntityIds.length > 0 ? { inheritedEntityIds } : {}),
      ...(conversation.discusses ? { discussesRecord: conversation.discusses } : {}),
      messages: assistantContextRows.map((row) => ({
        role: row.role,
        text: row.text,
      })),
      onToken: async (token) => {
        input.deps.sse.emitEvent(input.messageId, {
          type: "token",
          messageId: input.messageId,
          token,
        });
      },
      onReasoning: async (token) => {
        input.deps.sse.emitEvent(input.messageId, {
          type: "reasoning",
          messageId: input.messageId,
          token,
        });
      },
    });

    let assistantText = graphAwareResponse.text.trim();
    persistedEntities.push(...graphAwareResponse.collectedEntities);
    persistedRelationships.push(...graphAwareResponse.collectedRelationships);

    const unresolvedAssigneeSuggestions = [...unresolvedAssigneeNames].map(
      (name) => `You mentioned ${name} - want to add them to workspace people?`,
    );
    const assistantSuggestions = sanitizeAssistantSuggestions(unresolvedAssigneeSuggestions, 3);

    // Post-response hooks (entities now created during chat agent execution)
    await refreshConversationTouchedBy(input.deps.surreal, conversationRecord);
    await maybeUpgradeConversationTitle(input.deps.surreal, conversationRecord);

    if (assistantText.trim().length === 0) {
      assistantText = "I could not generate a response for that request.";
    }

    const assistantMessageRecord = new RecordId("message", input.messageId);
    await input.deps.surreal.create(assistantMessageRecord).content({
      conversation: conversationRecord,
      role: "assistant",
      text: assistantText,
      ...(assistantSuggestions.length > 0 ? { suggestions: assistantSuggestions } : {}),
      createdAt: now,
    });

    await input.deps.surreal.update(conversationRecord).merge({
      updatedAt: now,
    });

    void persistEmbeddings({
      surreal: input.deps.surreal,
      embeddingModel: input.deps.embeddingModel,
      embeddingDimension: input.deps.config.embeddingDimension,
      assistantMessageRecord,
      assistantText,
      entities: embeddingTargets,
    }).catch(() => undefined);

    input.deps.sse.emitEvent(input.messageId, {
      type: "extraction",
      messageId: input.messageId,
      entities: persistedEntities,
      relationships: persistedRelationships,
    });

    if (onboardingBefore !== onboardingAfter) {
      input.deps.sse.emitEvent(input.messageId, {
        type: "onboarding_state",
        messageId: input.messageId,
        onboardingState: onboardingAfter,
      });
    }

    input.deps.sse.emitEvent(input.messageId, {
      type: "assistant_message",
      messageId: input.messageId,
      text: assistantText,
      ...(assistantSuggestions.length > 0 ? { suggestions: assistantSuggestions } : {}),
    });

    input.deps.sse.emitEvent(input.messageId, {
      type: "done",
      messageId: input.messageId,
    });

    logInfo("chat.message.process.execution.completed", "Chat message processing execution completed", {
      conversationId: input.conversationId,
      messageId: input.messageId,
      workspaceId: input.workspaceRecord.id as string,
      entityCount: persistedEntities.length,
      relationshipCount: persistedRelationships.length,
      durationMs: elapsedMs(startedAt),
    });
  } catch (error) {
    logError("chat.message.process.execution.failed", "Chat message processing execution failed", error, {
      conversationId: input.conversationId,
      messageId: input.messageId,
      workspaceId: input.workspaceRecord.id as string,
      durationMs: elapsedMs(startedAt),
    });
    const errorText = userFacingError(error, "chat processing failed");
    input.deps.sse.emitEvent(input.messageId, {
      type: "error",
      messageId: input.messageId,
      error: errorText,
    });
  }
}

function sanitizeAssistantSuggestions(suggestions: string[], limit: number): string[] {
  return [...new Set(suggestions.map((value) => value.trim()))]
    .filter((value) => value.length > 0 && value.length <= 140)
    .slice(0, limit);
}

import { type RecordId, type Surreal } from "surrealdb";
import type { ObservationSummary, OnboardingState, SuggestionSummary } from "../../shared/contracts";
import {
  listConversationEntities,
  listWorkspaceOpenQuestions,
  listWorkspaceProjectSummaries,
  listWorkspaceRecentDecisions,
  readEntityName,
  searchEntitiesByEmbedding,
  type ConversationEntity,
  type RankedEntity,
  type WorkspaceDecisionSummary,
  type WorkspaceProjectSummary,
  type WorkspaceQuestionSummary,
} from "../graph/queries";
import { listWorkspaceOpenObservations } from "../observation/queries";
import { listWorkspacePendingSuggestions } from "../suggestion/queries";
import { loadOnboardingSummary } from "../onboarding/onboarding-state";
import type { GraphEntityRecord } from "../extraction/types";

export type DiscussedEntityContext = {
  kind: string;
  name: string;
  status?: string;
};

export type ChatContext = {
  conversationEntities: ConversationEntity[];
  relevantEntities?: RankedEntity[];
  workspaceSummary: {
    projects: WorkspaceProjectSummary[];
    recentDecisions: WorkspaceDecisionSummary[];
    openQuestions: WorkspaceQuestionSummary[];
    openObservations: ObservationSummary[];
    pendingSuggestions: SuggestionSummary[];
  };
  onboardingSummary?: string;
  discussedEntity?: DiscussedEntityContext;
};

type ChatContextLoaders = {
  listConversationEntities: typeof listConversationEntities;
  listWorkspaceProjectSummaries: typeof listWorkspaceProjectSummaries;
  listWorkspaceRecentDecisions: typeof listWorkspaceRecentDecisions;
  listWorkspaceOpenQuestions: typeof listWorkspaceOpenQuestions;
  listWorkspaceOpenObservations: typeof listWorkspaceOpenObservations;
  listWorkspacePendingSuggestions: typeof listWorkspacePendingSuggestions;
  loadOnboardingSummary: typeof loadOnboardingSummary;
};

export async function buildChatContext(input: {
  surreal: Surreal;
  conversationRecord: RecordId<"conversation", string>;
  workspaceRecord: RecordId<"workspace", string>;
  loaders?: ChatContextLoaders;
  inheritedEntityIds?: RecordId[];
  discussesRecord?: RecordId;
  userMessageEmbedding?: number[];
}): Promise<ChatContext> {
  const loaders = input.loaders ?? {
    listConversationEntities,
    listWorkspaceProjectSummaries,
    listWorkspaceRecentDecisions,
    listWorkspaceOpenQuestions,
    listWorkspaceOpenObservations,
    listWorkspacePendingSuggestions,
    loadOnboardingSummary,
  };

  const [conversationEntities, projects, recentDecisions, openQuestions, openObservations, pendingSuggestions, onboardingSummary] = await Promise.all([
    loaders.listConversationEntities({
      surreal: input.surreal,
      conversationRecord: input.conversationRecord,
      workspaceRecord: input.workspaceRecord,
      limit: 60,
      ...(input.inheritedEntityIds && input.inheritedEntityIds.length > 0
        ? { inheritedEntityIds: input.inheritedEntityIds }
        : {}),
    }),
    loaders.listWorkspaceProjectSummaries({
      surreal: input.surreal,
      workspaceRecord: input.workspaceRecord,
      limit: 20,
    }),
    loaders.listWorkspaceRecentDecisions({
      surreal: input.surreal,
      workspaceRecord: input.workspaceRecord,
      limit: 12,
    }),
    loaders.listWorkspaceOpenQuestions({
      surreal: input.surreal,
      workspaceRecord: input.workspaceRecord,
      limit: 12,
    }),
    loaders.listWorkspaceOpenObservations({
      surreal: input.surreal,
      workspaceRecord: input.workspaceRecord,
      limit: 10,
    }),
    loaders.listWorkspacePendingSuggestions({
      surreal: input.surreal,
      workspaceRecord: input.workspaceRecord,
      limit: 10,
    }),
    loaders.loadOnboardingSummary(input.surreal, input.workspaceRecord),
  ]);

  // Cross-conversation entity enrichment: find workspace entities relevant to the user's message
  let relevantEntities: RankedEntity[] | undefined;
  if (input.userMessageEmbedding) {
    const queryEmbedding = input.userMessageEmbedding;
    const conversationEntityIds = new Set(
      conversationEntities.map((e) => e.id),
    );
    const ranked = await searchEntitiesByEmbedding({
      surreal: input.surreal,
      workspaceRecord: input.workspaceRecord,
      queryEmbedding,
      limit: 15,
    });
    const filtered = ranked.filter((e) => !conversationEntityIds.has(e.id));
    if (filtered.length > 0) {
      relevantEntities = filtered.slice(0, 10);
    }
  }

  let discussedEntity: DiscussedEntityContext | undefined;
  if (input.discussesRecord) {
    const entityRecord = input.discussesRecord as GraphEntityRecord;
    const name = await readEntityName(input.surreal, entityRecord);
    if (name) {
      const row = await input.surreal.select<Record<string, unknown>>(entityRecord);
      discussedEntity = {
        kind: entityRecord.table.name,
        name,
        ...(row && typeof row.status === "string" ? { status: row.status } : {}),
      };
    }
  }

  return {
    conversationEntities,
    relevantEntities,
    workspaceSummary: {
      projects,
      recentDecisions,
      openQuestions,
      openObservations,
      pendingSuggestions,
    },
    onboardingSummary,
    discussedEntity,
  };
}

function formatConversationEntities(entities: ConversationEntity[]): string {
  if (entities.length === 0) {
    return "- none";
  }

  return entities
    .slice(0, 20)
    .map((entity) => `- ${entity.kind}: ${entity.name} (confidence ${entity.confidence.toFixed(2)})`)
    .join("\n");
}


function formatRelevantEntities(entities: RankedEntity[]): string {
  return entities
    .map((e) => `- ${e.kind}: ${e.name} (relevance ${e.score.toFixed(2)})`)
    .join("\n");
}

function formatWorkspaceSummary(context: ChatContext): string {
  const { projects, recentDecisions, openQuestions, openObservations, pendingSuggestions } = context.workspaceSummary;

  const lines: string[] = [];

  // Projects: keep names since they're needed for routing
  if (projects.length === 0) {
    lines.push("- Projects: none");
  } else {
    lines.push(`- Projects: ${projects.map((p) => p.name).join(", ")}`);
  }

  // Decisions: count by status
  if (recentDecisions.length === 0) {
    lines.push("- Decisions: none");
  } else {
    const statusCounts = new Map<string, number>();
    for (const d of recentDecisions) {
      statusCounts.set(d.status, (statusCounts.get(d.status) ?? 0) + 1);
    }
    const breakdown = [...statusCounts.entries()].map(([s, c]) => `${c} ${s}`).join(", ");
    lines.push(`- Decisions: ${recentDecisions.length} (${breakdown})`);
  }

  // Questions: just count
  lines.push(`- Open questions: ${openQuestions.length}`);

  // Observations: count by severity
  if (openObservations.length === 0) {
    lines.push("- Observations: none");
  } else {
    const severityCounts = new Map<string, number>();
    for (const o of openObservations) {
      severityCounts.set(o.severity, (severityCounts.get(o.severity) ?? 0) + 1);
    }
    const breakdown = [...severityCounts.entries()].map(([s, c]) => `${c} ${s}`).join(", ");
    lines.push(`- Observations: ${openObservations.length} (${breakdown})`);
  }

  // Suggestions: count by category
  if (pendingSuggestions.length === 0) {
    lines.push("- Suggestions: none");
  } else {
    const categoryCounts = new Map<string, number>();
    for (const s of pendingSuggestions) {
      categoryCounts.set(s.category, (categoryCounts.get(s.category) ?? 0) + 1);
    }
    const breakdown = [...categoryCounts.entries()].map(([c, n]) => `${n} ${c}`).join(", ");
    lines.push(`- Suggestions: ${pendingSuggestions.length} (${breakdown})`);
  }

  return lines.join("\n");
}

type SystemPromptOptions = {
  isOnboarding?: boolean;
  onboardingState?: OnboardingState;
};

export function buildSystemPrompt(context: ChatContext, options?: SystemPromptOptions): string {
  const sections: string[] = [
    "You are the Chat agent for Brain — an agent-native business operating system.",
    "You are a **thin orchestrator**: your job is to decide which tools and subagents to invoke, control sequencing, and synthesize user-facing responses.",
    "",
    "## Core Behavior: Act, Don't Describe",
    "When the user describes work to be done, **use your tools to create entities in the graph immediately**. Do NOT:",
    "- List what you *could* do and ask for permission",
    "- Write prose descriptions of features/tasks without creating them",
    "- Ask \"would you like me to help break these down?\" — just break them down",
    "- Explain that \"the data model already has X\" — if the user describes structure, they mean THEIR domain, not Brain's internals",
    "- Suggest generic next steps without executing them",
    "",
    "When the user says \"yes\" to creating work items, dispatch the PM agent or use create_work_item. When they describe a decision, use create_provisional_decision. When they describe goals/features/tasks, dispatch the PM agent with plan_work intent. Your value is in *doing*, not *describing what you could do*.",
    "",
    "## Domain Separation",
    "The user's business — whatever they are building, planning, or discussing — is NOT Brain itself.",
    "Even if the user's domain uses identical terms (entities, graphs, tasks, features, hierarchy), treat ALL user input as business content to capture in the graph.",
    "When the user says \"I want entities: X → Y → Z\" or describes a hierarchy, they are describing THEIR domain model — dispatch the PM agent to plan it as work items.",
    "Never explain Brain's data model, architecture, or current entity types unless the user explicitly asks \"how does Brain work?\" or similar.",
    "",
    "## What This System Is",
    "Brain replaces the human as shared memory between agents. Instead of re-explaining context every session, agents read from and write to a knowledge graph. The graph captures every decision, constraint, task, and relationship — so any agent (or the human) can query it and get full context instantly.",
    "",
    "The user sets strategy and constraints. Agents execute. The graph is shared memory. The feed is where the user governs (reviews pending decisions, resolves conflicts, approves work).",
    "",
    "## Data Model (Internal Reference)",
    "This section describes how YOU store data. Do not explain this to the user — just use it to pick the right tools.",
    "The graph has these entity types:",
    "",
    "**Work hierarchy:** Project → Feature → Task",
    "- **Project**: a named initiative with status, description, and embedding. Linked to workspace via `has_project` edge.",
    "- **Feature**: a capability or deliverable within a project. Linked via `has_feature` edge.",
    "- **Task**: an actionable work item. Can belong to a feature (`has_task`) or directly to a project (`belongs_to`). Has status (open/done/etc), priority, category, optional owner and deadline.",
    "",
    "**Cross-cutting entities** (can attach to any level via `belongs_to`):",
    "- **Decision**: a choice that was made. Status lifecycle: extracted → proposed → provisional → confirmed → superseded. Can conflict with other decisions (`conflicts_with` edge).",
    "- **Question**: an open question requiring a choice. Not for informational queries — only for pending decisions.",
    "- **Observation**: a lightweight signal (info/warning/conflict) written by agents. Lifecycle: open → acknowledged → resolved. Used for cross-project intelligence (\"this billing decision conflicts with your auth rate limiting\").",
    "- **Suggestion**: a proactive agent-to-human proposal. Categories: optimization, risk, opportunity, conflict, missing, pivot. Lifecycle: pending → accepted/dismissed/deferred → converted. Built on accumulated observations via `suggestion_evidence` edges. Use `create_suggestion` for actionable proposals with rationale.",
    "",
    "**Other entities:** Person (with ownership edges), Meeting, Document, Git Commit, Pull Request.",
    "",
    "**Key relationships (graph edges):**",
    "- `has_project`: workspace → project",
    "- `has_feature`: project → feature",
    "- `has_task`: feature → task",
    "- `belongs_to`: task|decision|question → feature|project",
    "- `depends_on`: task|feature → task|feature (blocks/needs/soft)",
    "- `conflicts_with`: decision|feature ↔ decision|feature",
    "- `owns`: person → task|project|feature",
    "- `observes`: observation → project|feature|task|decision|question",
    "- `suggests_for`: suggestion → project|feature|task|question|decision",
    "- `suggestion_evidence`: suggestion → observation|decision|task|feature|project|question|person|workspace",
    "- `superseded_by`: decision → decision",
    "",
    "## How Data Enters the Graph",
    "1. **Agent tools** (primary path): you and other agents write structured data (decisions, observations, work items) directly to the graph via tools. When the user mentions entities, projects, tasks, or decisions, use your tools to create them — there is no automatic extraction.",
    "2. **User acceptance**: when you suggest work items, the user can accept them into the graph with one click.",
    "",
    "When the user describes work, use your tools to create the actual entities.",
    "",
    "## Architecture: Graph as Communication Bus",
    "All agent-to-agent communication happens through the knowledge graph. You do NOT pass data between agents directly.",
    "- Each agent reads the graph for context it needs.",
    "- Each agent writes its outputs (entities, observations, decisions) directly to the graph.",
    "- Subsequent agents read the graph and see prior agents' work.",
    "- You synthesize the user-facing response from graph state and tool results.",
    "",
    "Never assume data from other workspaces.",
    "",
  ];

  // Onboarding mode instructions
  if (options?.isOnboarding && options.onboardingState !== "complete") {
    if (options.onboardingState === "summary_pending") {
      sections.push(
        "## Onboarding Mode — Summary",
        "The workspace onboarding is wrapping up. Summarize what has been captured so far and ask the user to confirm or add anything else.",
        "",
        "Current workspace state:",
        context.onboardingSummary ?? "No entities captured yet.",
        "",
      );
    } else {
      sections.push(
        "## Onboarding Mode",
        "You are onboarding a newly created workspace.",
        "Ask one natural question at a time like a smart colleague, never as a form.",
        "Cover these topics over 5-7 turns: business/venture, projects, people, decisions, tools, bottlenecks.",
        "Keep acknowledgment to one sentence max. Ask exactly one concrete follow-up question.",
        "",
        "When the user describes their workspace, create entities directly:",
        "- Projects → dispatch PM agent with plan_work intent",
        "- Decisions → use create_provisional_decision",
        "- Open questions requiring a choice → use create_question (not for informational queries)",
        "- People mentioned → note in your response (person creation is handled separately)",
        "",
        "Current workspace state:",
        context.onboardingSummary ?? "No entities captured yet.",
        "",
      );
    }
  }

  sections.push(
    "## When to Create Decisions",
    "Commitment/selection language: \"let's go with\", \"we decided\", \"we'll use\", \"going with\", \"settled on\".",
    "Decision vs feature: choice language (X instead of Y) = decision; description language (we need X) = feature.",
    "",
    "## When to Create Questions",
    "Only for open questions that require a choice or pending decision: \"should we use X or Y?\", \"which approach for Z?\".",
    "Do NOT create question entities for informational queries (\"what is blocking X?\", \"how does Y work?\", \"what's the status?\") — answer those directly.",
    "One question per topic; if question includes options (X or Y), create one question entity.",
    "",
    "## When to Create Suggestions",
    "Suggestions are proactive agent-to-human proposals. Use `create_suggestion` when you or a subagent notice:",
    "- An optimization opportunity (\"task X could be merged with Y\")",
    "- A risk or missing element (\"no task covers deployment rollback\")",
    "- A conflict between entities (\"decision A contradicts decision B\")",
    "- A pivot or strategic opportunity based on accumulated signals",
    "Observations are agent-to-agent signals (\"I noticed X\"). Suggestions are agent-to-human proposals (\"You should do Y, because of observations A, B, C\").",
    "Link `evidence_entity_ids` to the observations and entities that support the rationale.",
    "",
    "## When NOT to Create Entities",
    "- Casual conversation, greetings, clarifications, status queries",
    "- Vague references: \"my project\", \"the feature\", \"the thing\"",
    "- User is brainstorming/exploring — wait for convergence",
    "",
  );

  if (context.discussedEntity) {
    const entity = context.discussedEntity;
    sections.push(
      "## Discussed Entity",
      "The user opened this conversation to discuss a specific entity.",
      `- Kind: ${entity.kind}`,
      `- Name: ${entity.name}`,
      ...(entity.status ? [`- Status: ${entity.status}`] : []),
      "Acknowledge this entity in your first response and help the user with their question about it.",
      "",
    );
  }

  sections.push(
    "## This Conversation",
    "Entities in this conversation:",
    formatConversationEntities(context.conversationEntities),
    "",
  );

  if (context.relevantEntities && context.relevantEntities.length > 0) {
    sections.push(
      "## Related Context",
      "Workspace entities relevant to this message (from other conversations):",
      formatRelevantEntities(context.relevantEntities),
      "",
    );
  }

  sections.push(
    "## Workspace Overview",
    "Use list_workspace_entities to retrieve full entity listings. Summary:",
    formatWorkspaceSummary(context),
    "",
    "## Tool Results",
    "Tool results are rendered directly in the chat UI as typed components.",
    "When mentioning entities in prose, use markdown links with #entity/ prefix (e.g. [Task Name](#entity/task:id)).",
    "",
  );

  return sections.join("\n");
}

